
import React, { useEffect, useState } from 'react';
import {
    CRow,
    CCol,
    CCard,
    CCardHeader,
    CCardBody,
} from '@coreui/react';
import { settingsAppointments } from 'src/services/standardUsers/index';
import GenericTable from 'src/components/Generic.Table';
import AppointmentsC from './Appointments'
import i18n from 'src/i18n';
import { useSelector } from 'react-redux';
const Appointments = () => {
    const [List, setList] = useState([]);
const selectedUser = useSelector((state) => state.selectedUser.selectedUser);
    const fetchAppointments = async () => {
        try {
            const list = await settingsAppointments.getAppointments();
            if (list) {
                setList(list?.data);
            }
        } catch (error) {
            console.error('Error fetching admin list:', error);
        }
    };
    useEffect(() => {
        fetchAppointments();
    }, []);

    const columns = [
        { label: i18n.t('clientNameLabel'), field: 'client_name' },
        { label: i18n.t('clientContactLabel'), field: 'client_contact' },
        { label: i18n.t('appointmentDateLabel'), field: 'date' },
        { label: i18n.t('appointmentTimeLabel'), field: 'time' },
        { label: i18n.t('durationLabel'), field: 'duration' },
        { label: i18n.t('hardwareLabel'), field: 'hardware' },
        { label: i18n.t('softwareLabel'), field: 'software' },
        { label: i18n.t('reasonLabel'), field: 'meeting_reason' },
        { label: i18n.t('descriptionInputLabel'), field: 'description' },
        {
            label: i18n.t('actionLabel'),
            field: 'actions',
            render: (item) =>
            (
                <>

                    <AppointmentsC refresh={() => fetchAppointments()} selectedAppointments={item} />
                </>
            )
        },

    ];

    return (
        <CCard className="mb-4">
            <CCardHeader>
                <CRow className="align-items-center">
                    <CCol md="6" xs="12">
                        <strong>   {i18n.t('AppointmentsTableTitle')}</strong>
                    </CCol>
                    <CCol md="6" xs="12" className="text-md-end mt-md-0 mt-3">
                        <AppointmentsC refresh={() => fetchAppointments()} />
                    </CCol>
                </CRow>
            </CCardHeader>
            <CCardBody>
                <CRow>
                    <CCol xs="12">
                        <CCard className="mb-4">
                            <CCardHeader>
                                <strong>{i18n.t('AppointmentsList')}</strong>
                            </CCardHeader>
                            <CCardBody>
                                <GenericTable columns={columns} data={List} />
                            </CCardBody>
                        </CCard>
                    </CCol>
                </CRow>
            </CCardBody>
        </CCard>
    );
};

export default Appointments;

